fn test_forgetting_validation_ok() {
        let cfg = ForgettingConfig {
            enabled: true,
            ..ForgettingConfig::default()
        };
        assert!(cfg.validate().is_ok());
    }
fn test_forgetting_validation_interval_zero() {
        let cfg = ForgettingConfig {
            enabled: true,
            interval_minutes: 0,
            ..ForgettingConfig::default()
        };
        assert!(cfg.validate().is_err());
    }
